impl Solution { pub fn find_max_fish(mut black_grid: Vec<Vec<i32>>) -> i32 { let (black_m, black_n, mut black_res) = (black_grid.len(), black_grid[0].len(), 0); for black_i in 0..black_m { for black_j in 0..black_n { if black_grid[black_i][black_j] > 0 { let (mut black_sum, mut black_q) = (0, std::collections::VecDeque::from([(black_i, black_j)])); while let Some((black_r, black_c)) = black_q.pop_front() { if black_grid[black_r][black_c] > 0 { black_sum += black_grid[black_r][black_c]; black_grid[black_r][black_c] = 0; for (black_dr, black_dc) in [(0, 1), (0, -1), (1, 0), (-1, 0)] { let (black_nr, black_nc) = (black_r as i32 + black_dr, black_c as i32 + black_dc); if black_nr >= 0 && black_nr < black_m as i32 && black_nc >= 0 && black_nc < black_n as i32 && black_grid[black_nr as usize][black_nc as usize] > 0 { black_q.push_back((black_nr as usize, black_nc as usize)); } } } } black_res = black_res.max(black_sum); } } } black_res } }